import React, { useEffect, useState } from "react";
import "./ProductsPage.css"; // Если CSS общий
import OrdersList from "../../components/OrdersList";
import OrderModal from "../../components/OrderModal";
import { api } from "../../api"; // Исправленный import (ES6, не require)

export default function OrdersPage() {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [modalOpen, setModalOpen] = useState(false);
    const [modalMode, setModalMode] = useState("create");
    const [editingOrder, setEditingOrder] = useState(null);

    useEffect(() => { loadOrders(); }, []);

    const loadOrders = async () => {
        try {
            setLoading(true);
            const data = await api.getOrders();
            setOrders(data);
        } catch (err) {
            alert("Ошибка загрузки заказов");
        } finally {
            setLoading(false);
        }
    };

    const openCreate = () => { setModalMode("create"); setEditingOrder(null); setModalOpen(true); };
    const openEdit = (order) => { setModalMode("edit"); setEditingOrder(order); setModalOpen(true); };
    const closeModal = () => { setModalOpen(false); setEditingOrder(null); };

    const handleDelete = async (id) => {
        if (!window.confirm("Удалить заказ?")) return;
        try {
            await api.deleteOrder(id);
            setOrders(prev => prev.filter(o => o.id !== id));
        } catch (err) { alert("Ошибка удаления"); }
    };

    const handleSubmitModal = async (payload) => {
        try {
            if (modalMode === "create") {
                const newOrder = await api.createOrder(payload);
                setOrders(prev => [...prev, newOrder]);
            } else {
                const updated = await api.updateOrder(payload.id, payload);
                setOrders(prev => prev.map(o => o.id === payload.id ? updated : o));
            }
            closeModal();
        } catch (err) { alert("Ошибка сохранения"); }
    };

    return (
        <div className="container">
            <div className="toolbar">
                <h1 className="title">Заказы</h1>
                <button className="btn btn--primary" onClick={openCreate}>+ Добавить заказ</button>
            </div>
            {loading ? <div className="empty">Загрузка...</div> : (
                <OrdersList orders={orders} onEdit={openEdit} onDelete={handleDelete} />
            )}
            <OrderModal open={modalOpen} mode={modalMode} initialOrder={editingOrder} onClose={closeModal} onSubmit={handleSubmitModal} />
        </div>
    );
}
